export default function AboutBand() {
  return (
    <section className="about-band">
      <div className="about-inner">
        <h2>What is Kuppayam?</h2>
        <p>
          Kuppayam (കുപ്പായം) means "garment" in Malayalam. We believe every piece of clothing carries a story — of
          the hands that made it, the land it comes from, and the person who wears it. We make clothes that last,
          look good, and mean something.
        </p>
      </div>
    </section>
  );
}
